mapper.update:
update tbl_conversation_setting
set alias = #{alias}, updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

update tbl_conversation_setting
set is_muted = #{muted}, updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

mapper.select:
select coalesce(is_muted, false)
from tbl_conversation_setting
where conversation_id = #{conversationId} and member_id = #{memberId}

mapper.update:
update tbl_conversation_setting
set is_deleted = true,
    is_muted = false,
    alias = null,
    is_pinned = false,
    deleted_after_message_id = (
        select max(id) from tbl_message where conversation_id = #{conversationId}
    ),
    updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}
